previewCss:
.darma-loader-uiverse-radial-dash-clock {
  width: 48px;
  height: 48px;
  transform: rotate(0deg);
  animation: darma-loader-uiverse-radial-dash-clock-spin 2.4s linear infinite;
}

.darma-loader-uiverse-radial-dash-clock line {
stroke: var(--loader-color, #ffffff); /* White color for better visibility */
stroke-width: 4;
stroke-linecap: round;
opacity: 0.8;
stroke-dasharray: 10;
stroke-dashoffset: 10;
animation: darma-loader-uiverse-radial-dash-clock-dash 2.4s ease-in-out infinite;
}

@keyframes darma-loader-uiverse-radial-dash-clock-dash {
0% {
stroke-dashoffset: 10;
opacity: 0.8;
}
50% {
stroke-dashoffset: 0;
opacity: 0.4;
}
100% {
stroke-dashoffset: 10;
opacity: 0.8;
}
}

@keyframes darma-loader-uiverse-radial-dash-clock-spin {
0% {
transform: rotate(0deg);
}
100% {
transform: rotate(360deg);
}
}

